const getServicesList = async (contractInstance, account) => {
    let list = await contractInstance.methods.getServices().call({from:account});
    console.log("======getServicesList",list)
    return list;
}

const getServiceById = async (contractInstance, serviceId, account) => {
    let service = await contractInstance.methods.getServiceById(serviceId).call({from:account});
    return service;
}

const regService = async (contractInstance, account) => {
    let timestamp = Date.now();
    let tx = await contractInstance.methods.regService(account, 88, 1, `Me`, `Kovan Testnet Service-${timestamp}`, "https://avatars.githubusercontent.com/u/26024178?v=4", "This is the service for Kovan Testnet. Please feel free to use it.").send({from: account});
    console.log("regService====", tx);
}


const stake = async (contractInstance, web3Instance, serviceId, amount,account) => {
    let ret = await contractInstance.methods.stake(serviceId, web3Instance.web3Instance.utils.toWei(amount.toString())).send({from:account});
    console.log(ret);
    return ret;
}

const approve = async (contractInstance, web3Instance, amount,account,spender) => {
    let ret = await contractInstance.methods.approve(spender, web3Instance.web3Instance.utils.toWei(amount.toString())).send({from:account});
    return ret;
}

